import{_ as l,c as i,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const m=JSON.parse('{"title":"prompts.chat","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/prompts.chat-AI工具.md","filePath":"github汇总/AI工具/prompts.chat-AI工具.md"}'),t={name:"github汇总/AI工具/prompts.chat-AI工具.md"};function o(h,a,n,s,p,c){return e(),i("div",null,a[0]||(a[0]=[r('<h1 id="prompts-chat" tabindex="-1">prompts.chat <a class="header-anchor" href="#prompts-chat" aria-label="Permalink to “prompts.chat”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>prompts.chat</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>f</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>AI工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>用户在使用AI时不知道怎么写提示词，找不到好用的提示词模板，缺乏系统性的提示词学习资源。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>全球最大的开源AI提示词库，收录海量精选提示词示例，支持ChatGPT、Claude、Gemini、Llama、Mistral等多种AI模型。提供互动式提示词学习指南，包含25个章节，覆盖从基础到高级技巧如思维链推理、少样本学习、AI代理等。提供儿童互动游戏，教8到14岁孩子如何与AI交流。支持自托管部署，可搭建私有提示词库。提供CLI工具、Claude Code插件、MCP服务器等多种集成方式。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>全球最大开源AI提示词库</li><li>超过14万GitHub星标</li><li>被Forbes报道，被哈佛、哥伦比亚等名校引用</li><li>40多篇学术论文引用</li><li>Hugging Face上最受欢迎的数据集</li><li>GitHub Staff Pick</li><li>第一个提示词库（2022年12月创建）</li><li>提供互动式学习指南和儿童教育游戏</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><ul><li>143k+ GitHub stars</li><li>GitHub Staff Pick</li><li>Featured in Forbes</li><li>Referenced by Harvard, Columbia</li><li>40+ academic citations</li><li>Most liked dataset on Hugging Face</li><li>First prompt library (Dec 2022)</li></ul><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/f/prompts.chat" target="_blank" rel="noreferrer">https://github.com/f/prompts.chat</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要使用prompts.chat提示词库或自托管部署的用户。</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li><p><strong>检查Node.js版本</strong>（自托管需要）</p><ul><li>执行命令：<code>node -v</code></li><li>通过标准：显示Node.js版本号</li></ul></li><li><p><strong>检查npm是否安装</strong>（自托管需要）</p><ul><li>执行命令：<code>npm -v</code></li><li>通过标准：显示npm版本号</li></ul></li></ol><h3 id="主路径-直接使用在线版本-推荐" tabindex="-1">主路径：直接使用在线版本（推荐） <a class="header-anchor" href="#主路径-直接使用在线版本-推荐" aria-label="Permalink to “主路径：直接使用在线版本（推荐）”">​</a></h3><p><strong>步骤1：访问提示词库</strong></p><ul><li>目标：浏览和使用提示词</li><li>位置：浏览器</li><li>操作：访问 <a href="https://prompts.chat" target="_blank" rel="noreferrer">https://prompts.chat</a></li><li>成功标志：页面正常加载，可以看到提示词列表</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：浏览和使用提示词</strong></p><ul><li>目标：找到需要的提示词</li><li>位置：网页</li><li>操作：浏览分类或搜索关键词，点击提示词查看详情</li><li>成功标志：找到合适的提示词</li><li>失败处理：尝试不同的搜索关键词</li></ul><h3 id="备选路径1-使用cli工具" tabindex="-1">备选路径1：使用CLI工具 <a class="header-anchor" href="#备选路径1-使用cli工具" aria-label="Permalink to “备选路径1：使用CLI工具”">​</a></h3><p><strong>步骤1：运行CLI</strong></p><ul><li>目标：通过命令行访问提示词</li><li>位置：终端</li><li>命令：<code>npx prompts.chat</code></li><li>成功标志：CLI工具启动，显示提示词列表</li><li>失败处理：检查Node.js和npm是否正确安装</li></ul><h3 id="备选路径2-自托管部署" tabindex="-1">备选路径2：自托管部署 <a class="header-anchor" href="#备选路径2-自托管部署" aria-label="Permalink to “备选路径2：自托管部署”">​</a></h3><p><strong>步骤1：克隆项目</strong></p><ul><li>目标：获取项目源码</li><li>位置：本地开发目录</li><li>命令：<code>git clone https://github.com/f/prompts.chat.git</code></li><li>成功标志：项目目录创建成功</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：安装依赖</strong></p><ul><li>目标：安装项目依赖</li><li>位置：项目目录</li><li>命令：<code>cd prompts.chat &amp;&amp; npm install &amp;&amp; npm run setup</code></li><li>成功标志：依赖安装完成，设置向导启动</li><li>失败处理：检查npm版本</li></ul><p><strong>步骤3：启动服务</strong></p><ul><li>目标：启动自托管服务</li><li>位置：项目目录</li><li>命令：<code>npm run dev</code> 或 <code>npm start</code></li><li>成功标志：服务启动，可以访问本地地址</li><li>失败处理：检查端口是否被占用</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>在线版本：页面正常加载，可以浏览和搜索提示词</li><li>CLI版本：命令行显示提示词列表</li><li>自托管版本：本地服务正常启动，可以访问</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>CLI命令无法运行</strong></p><ul><li>可能原因：Node.js未安装或版本过低</li><li>解决步骤：安装或更新Node.js到最新LTS版本</li></ul></li><li><p><strong>自托管服务启动失败</strong></p><ul><li>可能原因：端口被占用</li><li>解决步骤：修改配置文件中的端口号</li></ul></li><li><p><strong>依赖安装失败</strong></p><ul><li>可能原因：网络问题或npm源问题</li><li>解决步骤：切换npm源为国内镜像</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://github.com/f/prompts.chat#-self-hosting" target="_blank" rel="noreferrer">Self-Hosting Guide</a> <a href="/网络环境.html">海外网络环境配置 →</a></li><li><a href="https://github.com/f/prompts.chat#-docker-guide" target="_blank" rel="noreferrer">Docker Guide</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',43)]))}const u=l(t,[["render",o]]);export{m as __pageData,u as default};
